import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { T, ACCENT, SEC, OTT, getNewsAccent, useAppTheme, API_BASE, YT_CHANNEL, APP_VERSION, apiCall, API, useAPI, useReveal, Reveal, AP_CONSTITUENCIES, TG_CONSTITUENCIES, NEWS_ITEMS, NEWS_CATS, REPORTERS, BULLETIN_SEGS, CLASSIFIEDS, CL_CATS, CL_CAT_EMOJI, CL_CAT_IMG, CL_BADGE_COLOR, NO_CALL_CATS, CL_SUBCATS, CONTACT_CATS, CHANNELS_AP, CHANNELS_TG, TICKER_TEXT, getChannelName, YT_CHANNEL_ID, YT_LIVE_KURNOOL, YT_LIVE_GUNTUR, YT_LIVE_NELLORE, YT_LIVE_KAKINADA, YT_LIVE_TIRUPATI, YT_LIVE_KHAMMAM, YT_LIVE_KARIMNAGAR, YT_LIVE_WARANGAL, YT_LIVE_NALGONDA, YT_LIVE_VIDEO, YT_LIVE_KNR, YT_LIVE_GTV, YT_LIVE_FALLBACK, CHANNEL_VIDEO, LIVE_CHANNELS, BULLETINS, PROGRAM_TYPES, PROGRAM_COLORS, SHORT_NEWS, CONSTITUENCY_DISTRICT, WISH_TYPES, CONTENT_TYPES, TE_LABEL_MAP, VEG_LIST, VEG_LIST_TE, AP_DISTRICTS, TG_DISTRICTS, css } from '../../_imports.js';

function BannerRotator({ onNavigate }) {
  const { T } = useAppTheme();
  const [active, setActive] = useState(0);

  const IMGS = [
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
    "data:image/jpeg;base64,",
  ];
  const ACTS = ["newsupload","birthdayform","carsales","jobs"];

  useEffect(()=>{
    const t = setInterval(()=>setActive(a=>(a+1)%4), 3000);
    return ()=>clearInterval(t);
  },[]);

  return (
    <div style={{position:"relative",overflow:"hidden"}}>
      <div key={active} onClick={()=>onNavigate(ACTS[active])}
        style={{cursor:"pointer",width:"100%",height:85,overflow:"hidden",animation:"fadeIn 0.35s ease"}}>
        <img src={IMGS[active]} alt="banner"
          style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"center",display:"block"}}/>
      </div>
      <div style={{display:"flex",justifyContent:"center",gap:5,padding:"5px 0",
        background:T.isDark?"#07101e":"#f0f4ff",borderBottom:`1px solid ${T.border}`}}>
        {[0,1,2,3].map(i=>(
          <div key={i} onClick={()=>setActive(i)}
            style={{width:i===active?18:6,height:6,borderRadius:3,cursor:"pointer",
              background:i===active?"#D0021B":"rgba(180,180,180,0.35)",transition:"all 0.3s"}}/>
        ))}
      </div>
    </div>
  );
}



export { BannerRotator };
export default BannerRotator;
